import{_ as r,o as e,c as a,a7 as o}from"./chunks/framework.BgApuQ2e.js";const s="/images/traveling-third-world-great-also-sucks/Venn-Final1.png",n="/images/traveling-third-world-great-also-sucks/logistics-goat-combo1-1024x460.png",l="/images/traveling-third-world-great-also-sucks/logistics-goat-3.png",p="/images/traveling-third-world-great-also-sucks/NY1.png",i="/images/traveling-third-world-great-also-sucks/food-combo.png",g="/images/traveling-third-world-great-also-sucks/destroyed-honor.png",h="/images/traveling-third-world-great-also-sucks/stray-animals.png",d="/images/traveling-third-world-great-also-sucks/salesman-1.png",c="/images/traveling-third-world-great-also-sucks/salesman-2.png",m="/images/traveling-third-world-great-also-sucks/toilets.png",u="/images/traveling-third-world-great-also-sucks/lucky.png",w="/images/traveling-third-world-great-also-sucks/douchebag.png",_="/images/traveling-third-world-great-also-sucks/pinit_fg_en_rect_gray_20.png",S=JSON.parse('{"title":"Traveling To The Third World Is Great And Also It Sucks","description":"","frontmatter":{"title":"Traveling To The Third World Is Great And Also It Sucks","titleZh":"去第三世界旅行既美妙又糟糕","date":"2014-04-29T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/04/traveling-third-world-great-also-sucks.html","slug":"traveling-third-world-great-also-sucks"},"headers":[],"relativePath":"posts/traveling-third-world-great-also-sucks.md","filePath":"posts/traveling-third-world-great-also-sucks.md","lastUpdated":1782886257000}'),f={name:"posts/traveling-third-world-great-also-sucks.md"};function k(b,t,y,v,T,W){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="去第三世界旅行既美妙又糟糕-·-traveling-to-the-third-world-is-great-and-also-it-sucks" tabindex="-1">去第三世界旅行既美妙又糟糕 · Traveling To The Third World Is Great And Also It Sucks <a class="header-anchor" href="#去第三世界旅行既美妙又糟糕-·-traveling-to-the-third-world-is-great-and-also-it-sucks" aria-label="Permalink to &quot;去第三世界旅行既美妙又糟糕 · Traveling To The Third World Is Great And Also It Sucks&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/04/traveling-third-world-great-also-sucks.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/04/traveling-third-world-great-also-sucks.html</a> · 2014-04-29</p></blockquote><p>生活在发达国家的人去发展中国家旅行,一方面是丰富的、开阔眼界、塑造视角的文化体验,另一方面则是糟透了。</p><p>你知道 Facebook 上那种让人心烦的人吧——就是发照片显摆自己在坦桑尼亚、印度或秘鲁做着某件看起来美味、美丽或狂野的活动?虽说他们发帖是出于自己的目的,是一场娴熟编织的<a href="https://waitbutwhy.com/2013/07/7-ways-to-be-insufferable-on-facebook.html" target="_blank" rel="noreferrer">形象打造和挑起嫉妒</a>大戏,但你坐在自己选的这个破生活里,还是忍不住心生向往?</p><p>你需要记住的是,他们对照片做了精心的裁剪——把痛苦裁掉了。当你去坦桑尼亚、印度或秘鲁这种国家,身体完全不适应当地生态时,痛苦是政府强制配套的,只是你不在那儿的时候很容易忘记这一点。</p><p>所以并不是说那位让你心烦的朋友玩得不开心——他们确实很开心——但在他们那副蠢兮兮张大嘴的欢喜笑容和高举双臂伸向瀑布多汁水雾的姿势之下,再往下几英尺,是酸痛起泡的脚、被携带疟疾的蚊子咬满包的腿,以及某种咕噜作响的腹泻噩梦。</p><p>你还是应该嫉妒的——只是别嫉妒得<em>那么</em>厉害。</p><p>我们暂停一下,来分辨一下「旅行」和「度假」的区别。</p><p>出门在外,你可以专注于三件事:</p><p><strong>1) 地方。</strong> 探索一个地方的著名景点、自然奇观、历史和现代亮点。</p><p><strong>2) 人。</strong> 了解当代文化和当地人的思维方式;通过提问、走访居民区、跟当地人打成一片,来更好地理解在那里生活是什么感觉。</p><p><strong>3) 自己。</strong> 享乐主义,专注于吃、喝、阅读和放松。</p><p>世界上任何地方,一个容易着迷的人都能实现 #1,一个勇敢外向的人都能实现 #2,而如果你预算够高,几乎在任何地方都能实现 #3。</p><p>但对普通人来说,这三个目标里哪个能轻松达成,取决于具体去哪儿。以下是一些最自然能达成对应目标的地方举例:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/Venn-Final1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="What you can get out of a trip"></a></p><p>** A) 真的。B) 我去过那儿,所以我不是在瞎讲怪话。C) 用它讲这个笑话是个好选择,因为哈萨克斯坦的 Wait But Why 读者不多,所以我因此惹的麻烦相对较少。</p><p>所以说到旅行 vs 度假——</p><p>一次旅行要够格被称为「度假 (vacation)」,享乐主义(上文第 3 项)必须是核心组成部分,而痛苦基本不该出现在方程式里。度假应当给你的电池和健康充电。而且度假是没什么争议的,它就是好的。<a href="#footnote-1-1444">1</a> 但它的效果也比较停留在表面,可能不太持久。</p><p>「旅行 (traveling)」呢,我的定义就完全不一样了。一次「旅行」的核心必须是第 1 项、第 2 项,或者两者兼有。享乐有时候可以是旅行的一部分,但它不是你去那儿的原因,而且你结束行程时很可能不会觉得神清气爽——你会觉得自己需要一次度假。旅行不像度假那样一致地「好」——有些瞬间会好得让人震撼,另一些则会是你一整年里最糟的部分。但不管发生了什么,它可能会留下来,成为你这个人的一部分。</p><p>这篇文章讲的是旅行,尤其是那种最典型的「旅行」体验——最能同时命中第 1 项和第 2 项(通常又完全错过第 3 项)的那种——第三世界旅行。具体来说,是一个第一世界的访客所体验到的第三世界旅行。</p><p>(「第一世界 (First World)」和「第三世界 (Third World)」这两个词,有可能是冒犯性的。我也说不准。我谷歌了一下,感觉大概还有两年左右这两个词才会正式变成冒犯性用语——所以我打算趁还能用的时候多用几次,因为「发达国家 (Developed World)」和「发展中国家 (Developing World)」这两个词实在是没意思多了。)</p><p>(这些术语起源于冷战时期,当时和美国、资本主义站在一边的国家叫做第一世界,和苏联阵营、共产主义站在一边的国家叫做第二世界。不结盟国家就是第三世界,从那以后,「第一世界」和「第三世界」就有了新含义,分别指代发达国家和发展中国家。)</p><p>(把这篇文章大声读出来会是六岁的 Tim 最大的噩梦。「World」是我小时候第二难念对的单词,仅次于「girl」。我记得当时觉得,谁要是能把「girl」念对,那简直厉害到不可思议。跳过跳过。)</p><p>一个第一世界人可以期待从第三世界之旅中获得的 8 件事</p><p><strong>1)规矩没那么多。</strong></p><p>你基本上可以随便走进各种地方,可以开在错误的车道上,可以在街上喝酒,想干嘛就干嘛,没人管你。在缅甸的某些国内航班上,连安检都没有。</p><p>而在痛苦这一面……<strong>同样的结构缺失也能让整件事变成一场后勤上的噩梦。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/logistics-goat-combo1.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="Rules"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/logistics-goat-3.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Rules 3"></a></p><p><strong>2)如果你比较友善,认识当地人并不难。</strong></p><p>我承认,我之所以觉得这是真的,可能是因为<em>我</em>本来就先表现得更友好——因为我<em>认为</em>其他国家的人更友好,然后他们也就投桃报李。但不管怎样,仅仅因为我笑脸相迎、主动搭话,就被邀请进过几十个第三世界国家的家里。有一次,一家人挤在一间小公寓里,全家都睡在厨房,把他们唯一的卧室让给我(我苦苦推辞也没用)。而在纽约,还没有一个陌生人邀请过我去任何地方。</p><p><img src="'+p+'" alt="Unfriendly New York"></p><p>这就是为什么第三世界国家在上面那张维恩图的「人」这一部分,表现得比第一世界国家好那么多。</p><p>在痛苦的一面……<strong>如果你不学几句当地的话,语言障碍会毁掉一切。</strong></p><p><strong>3) 食物往往超棒,而且和你熟悉的完全不一样。</strong></p><p>在痛苦的一面……<strong>食物也可能很吓人。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/food-combo.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Food"></a></p><p><strong>4) 那里的文化通常对你来说完全陌生,让你大开眼界、着迷不已。</strong></p><p>我喜欢这样想:我生活的世界,是几百年来某一群特定人类以及他们摸索出的一套生活方式的产物。当我去到一个真正不同的文化中时,就是一次机会,去看看另一群完全不同的人类,当<em>他们</em>自己去琢磨「怎么过日子」这个问题时,最终得出了什么答案。还有什么比这更吸引人的?</p><p>在痛苦的一面……<strong>你可能会无意中犯下某种可怕的文化禁忌。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/destroyed-honor.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="Violating a Taboo"></a></p><p><strong>5) 有酷炫的动物。</strong></p><p>我似乎经常在第三世界的地方碰到大象、(被麻醉的) 老虎、眼镜蛇、鸸鹋,以及各种猴子和猿类。在我老家可没多少这种机会。</p><p>在痛苦的一面……<strong>到处都是让人头疼的流浪动物。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/stray-animals.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="Stray Animals"></a></p><p><strong>6) 你能买到别处买不到的绝妙手工艺品。</strong></p><p>在痛苦的一面……<strong>你就是那些死缠烂打的店主的猎物。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/salesman-1.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="Salesman 1"></a><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/salesman-2.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Salesman 2"></a></p><p><strong>7) 它会提醒你,你老家住的其实是个宫殿,而这一切你根本没做过什么就白得了。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/toilets.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt="Third World Toilets"></a></p><p>只要在第三世界国家待上一小段时间,回家后你就会被自己享受的生活品质震撼得说不出话——街道一尘不染、超市里琳琅满目、一切都舒适到极点——第一世界那种巨大的富足感突然在你目光所及之处赤裸裸地显现,你会想起你认识的每一个人都过着国王般的生活却毫无察觉。然后两天之后,你也忘了,又开始抱怨这抱怨那。</p><p>而在痛苦这一面……<strong>它会提醒你,你在家里住的是宫殿,而你并没有做任何配得上这一切的事。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/lucky.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="Lucky not special"></a></p><p><strong>8) 你不会成为那种无知的第一世界人,以为去第三世界很危险,或者对第三世界国家有各种离谱的误解。</strong></p><p>如果你运用在自己家乡保命的那点常识,去第三世界国家旅行的危险系数是零。任何跟你说别的话的人,要么是过度偏执,要么就是旅行经验极少。</p><p>而在痛苦这一面……<strong>你有可能变成一个自以为是的傻叉,过分地为自己的第三世界经历感到自豪。</strong></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2014/04/douchebag.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="Self-Righteous"></a></p><p><strong>Wait But Why 其他关于旅行的文章:</strong></p><p><a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">我在朝鲜学到的 20 件事 (20 Things I Learned When I Was in North Korea)</a></p><p><a href="https://waitbutwhy.com/2013/07/12-types-of-people-youll-find-in-every.html" target="_blank" rel="noreferrer">每个青年旅舍里你都会遇到的 12 种人 (The 12 Types of People You&#39;ll Find in Every Hostel)</a></p><h2 id="奇怪地方里的奇怪事物-odd-things-in-odd-places" tabindex="-1"><a href="https://waitbutwhy.com/2014/09/odd-things-odd-places-7-travel-posts.html" target="_blank" rel="noreferrer">奇怪地方里的奇怪事物 (Odd Things in Odd Places)</a> <a class="header-anchor" href="#奇怪地方里的奇怪事物-odd-things-in-odd-places" aria-label="Permalink to &quot;[奇怪地方里的奇怪事物 (Odd Things in Odd Places)](https://waitbutwhy.com/2014/09/odd-things-odd-places-7-travel-posts.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,可以订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章一出来我们就发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li>除非你和错误的人一起旅行。但那是完全另一篇文章的话题了。<a href="#note-1-1444">↩</a></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/04/traveling-third-world-great-also-sucks.html&amp;description=Traveling%20To%20The%20Third%20World%20Is%20Great%20And%20Also%20It%20Sucks" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p>',67)])])}const I=r(f,[["render",k]]);export{S as __pageData,I as default};
